"use strict";(globalThis.webpackChunkcodeeatcode_github_io=globalThis.webpackChunkcodeeatcode_github_io||[]).push([[3874],{7577(e,t,a){a.r(t),a.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>u,frontMatter:()=>s,metadata:()=>n,toc:()=>l});var n=a(3988),o=a(4848),i=a(8453);const s={title:"Your Codebase Has Rules. Does CI Know That?",slug:"your-codebase-has-rules-does-ci-know-that",date:new Date("2026-05-21T06:00:00.000Z"),authors:["ambersariya"],tags:["python","testing","architecture","ai-engineering"]},r=void 0,h={authorsImageUrls:[void 0]},l=[];function c(e){const t={a:"a",code:"code",em:"em",p:"p",pre:"pre",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsxs)(t.p,{children:["There's a particular kind of meeting that happens on mixed teams. Someone's opened a pull request, and two engineers are staring at the same diff with completely different facial expressions. One is confused. The other is quietly furious. Neither is wrong, exactly \u2014 they just have entirely different mental models of what the codebase is ",(0,o.jsx)(t.em,{children:"supposed"})," to look like."]}),"\n",(0,o.jsx)(t.p,{children:"That's the drift I'm talking about. Not bugs. Not broken tests. Just two people who've been building in the same repository for months and have somehow ended up with incompatible ideas about what goes where."}),"\n",(0,o.jsx)(t.p,{children:"The friction tends to come from different professional histories. Engineers who came up through software development often have layered architecture drilled in early. Engineers who came up through data science and ML often optimised for iteration speed over structure. Neither background is wrong \u2014 they just don't automatically agree on where things belong."}),"\n",(0,o.jsxs)(t.p,{children:["The answer, at least in part, is ",(0,o.jsx)(t.a,{href:"https://github.com/jwbargsten/pytest-archonon",children:"pytest-archon"}),'. It lets you write tests that assert structural rules about your codebase. Not "does this function return the right value" \u2014 more like "nothing in the API layer should reach directly into the database layer." Rules you\'d normally write in a wiki nobody reads, enforced as a test that CI will actually fail on.']}),"\n",(0,o.jsx)(t.p,{children:"Here's what that looks like:"}),"\n",(0,o.jsx)(t.pre,{children:(0,o.jsx)(t.code,{className:"language-python",children:'from pytest_archon import archrule\n\ndef test_api_does_not_import_database():\n    (\n        archrule("api-layer-isolation")\n        .match("myapp.api.*")\n        .should_not_import("myapp.database.*")\n        .check("myapp")\n    )\n'})}),"\n",(0,o.jsx)(t.p,{children:"That's it. That test will fail if anyone \u2014 human or otherwise \u2014 writes an API handler that imports a database model directly. No relying on the comment thread getting resolved. No wiki page that's accurate until it isn't. The build fails. The feedback is immediate."}),"\n",(0,o.jsxs)(t.p,{children:["Which brings me to the agentic angle, because this isn't just about human engineers anymore. When you're vibe-coding with an agent generating chunks of your codebase, the agent doesn't inherently know your architectural rules. It knows how to write Python. It does not know that your team decided six months ago that services should never instantiate repositories directly. Architecture tests give it the same feedback signal they give a human: ",(0,o.jsx)(t.em,{children:"that's not how we do it here, try again."})]}),"\n",(0,o.jsx)(t.p,{children:"The rules become the documentation. Living documentation, with teeth. If the structure is correct, the tests pass. If it drifts \u2014 whether from a human in a hurry or an agent that didn't know better \u2014 they don't."}),"\n",(0,o.jsx)(t.p,{children:"We caught no bugs this way. We caught something slower and harder to fix than bugs: a gradual divergence in how the team understood the system. An AI engineer pulling in a service directly from an API handler because that's how you'd do it in a notebook. A software engineer quietly losing the will to review it because the conversation about why it's wrong is long and the PR queue is longer."}),"\n",(0,o.jsx)(t.p,{children:"Architecture tests remove the conversation. The boundary is in the codebase. The codebase enforces it. Everyone, human and agent alike, gets the same feedback."}),"\n",(0,o.jsx)(t.p,{children:"Getting ahead of drift is worth more than most people give it credit for."})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}},8453(e,t,a){a.d(t,{R:()=>s,x:()=>r});var n=a(6540);const o={},i=n.createContext(o);function s(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),n.createElement(i.Provider,{value:t},e.children)}},3988(e){e.exports=JSON.parse('{"permalink":"/your-codebase-has-rules-does-ci-know-that","source":"@site/blog/Your Codebase Has Rules Does CI Know That.md","title":"Your Codebase Has Rules. Does CI Know That?","description":"There\'s a particular kind of meeting that happens on mixed teams. Someone\'s opened a pull request, and two engineers are staring at the same diff with completely different facial expressions. One is confused. The other is quietly furious. Neither is wrong, exactly \u2014 they just have entirely different mental models of what the codebase is supposed to look like.","date":"2026-05-21T06:00:00.000Z","tags":[{"inline":true,"label":"python","permalink":"/tags/python"},{"inline":true,"label":"testing","permalink":"/tags/testing"},{"inline":true,"label":"architecture","permalink":"/tags/architecture"},{"inline":true,"label":"ai-engineering","permalink":"/tags/ai-engineering"}],"readingTime":2.53,"hasTruncateMarker":true,"authors":[{"name":"Danish Javed","title":"Software Engineer","url":"https://github.com/ambersariya","imageURL":"https://avatars.githubusercontent.com/u/1080238?s=400&u=5d6212c54765773934d34b3e55908846c9cd4a42&v=4","key":"ambersariya","page":null}],"frontMatter":{"title":"Your Codebase Has Rules. Does CI Know That?","slug":"your-codebase-has-rules-does-ci-know-that","date":"2026-05-21T06:00:00.000Z","authors":["ambersariya"],"tags":["python","testing","architecture","ai-engineering"]},"unlisted":false,"prevItem":{"title":"The Art of the Architecture Diagram Is Knowing What to Leave Out","permalink":"/the-art-of-the-architecture-diagram-is-knowing-what-to-leave-out"},"nextItem":{"title":"You Can\'t Debug What Bedrock Swallowed","permalink":"/you-cant-debug-what-bedrock-swallowed"}}')}}]);